class Solution:
    def maxSum(self, nums):
        n = len(nums)
        best = None
        for mask in range(1, 1 << n):
            vals = [nums[i] for i in range(n) if mask & (1 << i)]
            if len(set(vals)) != len(vals):
                continue
            s = sum(vals)
            if best is None or s > best:
                best = s
        return best

