var maxSum = function(nums) {
    const s = new Set(nums);
    let posSum = 0;
    let anyPos = false;
    for (const v of s) {
        if (v > 0) { posSum += v; anyPos = true; }
    }
    if (anyPos) return posSum;
    return Math.max(...nums);
};
